Use ASP.NET Core's **`WebApplicationFactory<T>`** — it spins up your app in-memory with no real ports. Here's the pattern:

**1. Add the test package**

```bash
dotnet add reference ../YourMcpServer/YourMcpServer.csproj
dotnet add package Microsoft.AspNetCore.Mvc.Testing
dotnet add package xunit
```

**2. Create a test fixture**

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("serverInfo", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsAvailableTools()
    {
        // Initialize first (MCP requires it)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list"
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeSession()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        var resp = await _client.PostAsJsonAsync("/mcp", init);
        resp.EnsureSuccessStatusCode();
    }
}
```

**Key points:**

- **`WebApplicationFactory<Program>`** boots your real `Program.cs` pipeline in-process — middleware, DI, routing all run as in production.
- **`/mcp`** — adjust the path to match your server's MCP endpoint.
- **Session state** — if your server uses the `Mcp-Session-Id` header (Streamable HTTP transport), capture it from the `initialize` response and attach it to subsequent requests.
- **SSE responses** — if your endpoint returns `text/event-stream`, read with `response.Content.ReadAsStreamAsync()` and parse `data:` lines instead of using `ReadFromJsonAsync`.
- **Mock external deps** — override services in the factory if needed:

```csharp
factory.WithWebHostBuilder(builder =>
{
    builder.ConfigureServices(services =>
    {
        services.AddSingleton<IMyDep>(new FakeDep());
    });
});
```

This gives you full protocol-level integration tests with zero network overhead.
